import { Injectable, signal } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class LoginSignalService {
  // Private signals
  private _userName = signal<string>('');
  private _role = signal<string>('');
  private _uuid = signal<string>('');
  private _otpNreset = signal<boolean>(false);

  // Public readonly signals (getters)
  readonly userName = this._userName;
  readonly role = this._role;
  readonly uuid = this._uuid;
  readonly otpNreset = this._otpNreset;

  // Setters
  setUserName(name: string) {
    this._userName.set(name);
  }

  setRole(role: string) {
    this._role.set(role);
  }

  setuuid(uuid: string) {
    this._uuid.set(uuid);
  }

  setOtpNReset(flag: boolean) {
    this._otpNreset.set(flag);
  }
}
